var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아아, 이게 어떻게 된 일일까! 조디악 나이츠가 파죽지세로 밀어붙이고 있다구!!","JPN":"ああっ、これはどういうことだ！　ゾディアックナイツが破竹の勢いで押し寄せてるよ！！","ENG":"Oh? What's going on here?! The Zodiac Knights are running their opponents to a corner with unstoppable force!","TWN":"喔喔～這是怎麼回事！十二宮騎士團可以說是勢如破竹呢！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"기습도, 속임수도 없는 정공법!! 하지만 빈틈이 보이지 않는다!!","JPN":"奇襲も、騙しもない正攻法！　でも隙が見えない！！","ENG":"No ambushes, no trickery! Just a full-on attack! But their attacks are airtight!","TWN":"沒有偷襲，也沒有耍小手段，他們選擇正面迎戰！！但是卻找不到任何漏洞！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"과연 조디악 나이츠!! 이번 경기에서 우승하여 불명예스러운……!","JPN":"果たして、ゾディアックナイツ！！　この試合で優勝して、不名誉な……！","ENG":"Incredible, Zodiac Knights!! By winning this match, maybe they'll be able to–!","TWN":"究竟十二宮騎士團！！能夠在這次的比賽中一雪前……！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 언니 힘내세요!!","JPN":"フィオネさん、頑張って！！","ENG":"Give it your all, Fione!!","TWN":"菲奧尼姊姊加油！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경도!! 한솔 경도!! 모두 모두 파이팅이에요!! 파이팅!!","JPN":"リブさんも！　ヤガミ卿も！！　みんなみんなファイトです！！　ファイト！！","ENG":"You too, Dame Liv and Sir Hansol!! Don't stop! I'm rooting for you all!!","TWN":"莉芙卿！！楊瀚卿！！你們也要加油！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"우린 할 수 있어요!","JPN":"私たちならできます！","ENG":"We can do this!","TWN":"我們辦得到的！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■</color> 방방 뛰는 거봐! 너무 귀엽잖아!\\n<color=#ffd34c>■■</color> 에리어스도 파이팅!!\\n<color=#ffd34c>■■■</color> 조디악 나이츠 생각보다 진짜 잘한다!\\n<color=#ffd34c>■■■</color> 카나리아가 아무것도 못하고 있어!\\n<color=#ffd34c>■ ■</color> 함선을 아예 못 쓰는 거 보면, 전 경기에 여파가 있나봐.","JPN":"<color=#ffd34c>■■</color> ピョンピョン跳ねてる！　可愛すぎ！\\n<color=#ffd34c>■■</color> アリウスもファイト！！\\n<color=#ffd34c>■■■</color> ゾディアックナイツ、思ったより上手じゃん！\\n<color=#ffd34c>■■■</color> カナリアは何もできてないよ！\\n<color=#ffd34c>■ ■</color> 艦船を全然使えてないのを見ると、この前の試合が響いてるようだな。","ENG":"<color=#ffd34c>■■</color> She's so cute jumping up and down like that!\\n<color=#ffd34c>■■</color> I'm rooting for you, Arius!!\\n<color=#ffd34c>■■■</color> The Zodiac Knights are doing better than I thought!\\n<color=#ffd34c>■■■</color> The Canary is unable to do anything!\\n<color=#ffd34c>■ ■</color> Seeing how they're not using their ship, the aftermath of their last match seems to be affecting them more than they thought.","TWN":"<color=#ffd34c>■■</color> 蹦蹦跳跳的好可愛！！\\n<color=#ffd34c>■■</color> 埃里奧斯也加油！！\\n<color=#ffd34c>■■■</color> 十二宮騎士團真的比想像中還厲害欸！\\n<color=#ffd34c>■■■</color> 金絲雀根本無法還手！\\n<color=#ffd34c>■ ■</color> 上一場比賽衝動的結果，就是無法使用艦船。"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"으으! 안 돼! 이러다간 내 방송 분량이!","JPN":"うう！　ダメ！　これじゃ、私の存在感が！","ENG":"Eergh! No! My screen time!","TWN":"呃呃！不行！這樣我的直播會沒東西可以播！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전원, 스피어헤드 대열을 유지합니다!!","JPN":"総員、スピアヘッドの隊列を維持します！！","ENG":"Knights! Maintain the spear formation!","TWN":"大家，保持隊形！！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"여기서 적의 방어선을 끊어내는 겁니다!! 적 함선은 제 기능을 하지 못하고 있어요!","JPN":"ここで敵の防御線を断ち切るのです！！　敵の艦船はちゃんと機能していません！","ENG":"This is where we sever the enemy's defense line!! Their ship is having trouble functioning!","TWN":"我們要在這裡突破敵人的防線！！對方的艦船現在無法正常使用！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_A","text":{"KOREA":"대열을 유지하라!","JPN":"隊列を維持しろ！","ENG":"Keep formation!","TWN":"維持隊形！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"적의 공격을 두려워하지 마라!","JPN":"敵の攻撃に怯えるな！","ENG":"Do not fear the enemy's attack!","TWN":"不要畏懼敵人的攻擊！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"으윽!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃呃！？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮아? 말콤 아저씨!?","JPN":"大丈夫？　マルコムさん！？","ENG":"Malcom! Are you all right?!","TWN":"大叔你沒事吧！？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"생각보다 갑옷이 튼튼하네요. 이러다간 도폭선이 먼저 바닥나겠어요.","JPN":"思ったより鎧が固いですね。これでは、導爆線が先に尽きてしまいます。","ENG":"Their armor is tougher than I thought. At this rate, I'll run out of detonation cords first.","TWN":"沒想到盔甲蠻堅固的，這樣下去導火線會先見底的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"이봐! 아무리 이기고 싶어도 폭약은 너무 비겁한 거 아니야!?","JPN":"ちょっと！　いくら勝ちたいからって、爆薬はズルすぎない！？","ENG":"Hey! No matter how much you want to win, don't you think explosives are a little below the belt?!","TWN":"喂！就算你再怎麼想贏，也不應該用炸藥吧！好奸詐！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"비겁하다고요? 그럼 이건 어떨까요?","JPN":"ズルい？　それでは、これはどうでしょう。","ENG":"Below the belt? Then what about this?","TWN":"奸詐？那換成這個呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"켈록! 켈록! 이, 이게 뭐야!?","JPN":"ゲホッ！　ゲホッ！　な、何これ！？","ENG":"*Cough!* *Cough!* W-what's this?!","TWN":"咳咳！咳咳！這，這是什麼！？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_STEAM"},{"id":"L35_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"민트 연막탄입니다. 그라운드 원에 있는 어느 카페 메뉴에서 영감을 받았죠.","JPN":"ミントの煙幕弾です。グラウンド・ワンにあるカフェのメニューからひらめきました。","ENG":"It's a mint smoke grenade. A cafe menu in Ground One inspired me to make it.","TWN":"這是薄荷煙霧彈，這是我從G1某間咖啡廳的菜單上得到的靈感。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으, 으아아! 너무 매워서 코가 따가워!","JPN":"う、わああ！　辛すぎて鼻がツンツンする！","ENG":"A-aaagh! It's stinging my nose!","TWN":"呃啊啊！煙霧好刺激，眼睛好痛！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"매설한 폭약과 지뢰를 쓰지 못하는 이상, 이쪽 루트는 병력을 묶어두는 게 전부에요.","JPN":"埋めておいた爆薬と地雷を使えなくなった以上、こちらのルートは兵力の足止めしかできません。","ENG":"If I can't use the mines and explosives I planted, all I can do on this route is tie their troops up.","TWN":"既然無法使用事先埋好的炸藥和地雷，那我最多就只能把敵人困在這裡。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"도폭선이 떨어지면, 이쪽도 밀릴 수밖에 없어요.","JPN":"導爆線が尽きたら、こちらも押されるでしょう。","ENG":"Once I run out of detonation cords, this place will be overrun by the enemy.","TWN":"導火線用光的話我也無計可施。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"미안하지만, 이쪽도 마냥 한가하진 않거든!","JPN":"悪いが、こっちも暇じゃねえんだよ！","ENG":"Sorry, but I'm a tad busy here at the moment!","TWN":"不好意思喔，我也沒閒著欸！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 녀석들 기세가 장난이 아니야!","JPN":"こいつら、すげー勢いだ！","ENG":"These blokes are no joke!","TWN":"這些傢伙的氣勢真不是蓋的！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……흣!?","JPN":"……ふっ！？","ENG":"...Heut?!","TWN":"……唔！？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"혼신의 일격이었는데 피하다니, 역시 대단하시네요.","JPN":"渾身の一撃を避けるなんて、流石ですね。","ENG":"Impressive. You dodged my final strike.","TWN":"竟然能夠躲過我的全力一擊！厲害厲害。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아니 방금 세 번 휘둘렀잖아! 그리고 혼신의 일격이라는 말도 벌써 다섯 번째거든?","JPN":"いや、今3回振り回しただろ！　それに、渾身の一撃って言葉ももう5回目だぜ？","ENG":"You swung at me three times! Also, you've used the word \\"final strike\\" five times already!","TWN":"拜託，你剛都已經揮三次咧！而且全力一擊！這句話你已經說過五次咧？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"넌 지치지도 않냐? 왜 그렇게 진지해?","JPN":"お前、疲れねえの？　なんでそんなに真剣なんだ？","ENG":"Don't you get tired? Why are you so serious?","TWN":"你不累嗎？這麼認真幹嘛？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"당연하죠. 저희는 오늘 반드시 이길 겁니다.","JPN":"当たり前でしょう。我々は今日、必ず勝ちます。","ENG":"Of course, I'm serious. We are going to win this no matter what.","TWN":"必須的，我們今天一定要拿下勝利。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이기지 못하면, 그동안 매일 같이 단련해온 의미가 없으니까!","JPN":"勝てないと、今まで毎日鍛えてきた意味がありませんから！","ENG":"If we don't win, then all the days I spent training would be for nothing!","TWN":"輸掉的話，我們過去每天的練習就會化為烏有！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇, 하필 제일 귀찮은 타입이랑 붙었잖아?","JPN":"チッ、よりによって一番面倒なタイプを相手することになっちまったな。","ENG":"Tch! I just had to match up with the most annoying type, eh?","TWN":"嘖，偏偏對上這種最麻煩的類型。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"S급 청소요원 님! 오른쪽으로 피하세요!","JPN":"S級の掃除エージェントさん！　右に避けてください！","ENG":"Mr. Grade S cleaning agent! Jump to your right!","TWN":"S級清潔特工先生！往右邊躲開！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"특이한 무기! 상대 스나이퍼가 저격하고 있어요!","JPN":"変わった武器ですね！　相手のスナイパーが狙撃しています！","ENG":"What a strange weapon! The opposing sniper has started shooting!","TWN":"好特別的武器！對方的狙擊手正在進行攻擊！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"모두 머리 숙이고 방패를 올려요!","JPN":"みんな、頭を下げて盾を上げてください！","ENG":"Everyone, lower your heads and raise your shields!","TWN":"大家舉起盾牌掩護好自己！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헷, 노엘이라고 했던가? 솜씨가 나쁘지 않은데?","JPN":"ヘッ、ノエルだったか？　なかなかやるな。","ENG":"Heh. Noelle, was it? Not bad, kid.","TWN":"嘿，你叫洛艾兒嗎？身手不錯喔？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"설마! 승부에서 도망치는 건가요!","JPN":"まさか！　勝負から逃げるのですか！","ENG":"Wait! You're not running away from a fight, are you?","TWN":"難道！你是要從戰場上逃走嗎！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야! 말 똑바로 해, 범생아! 이건 작전상 후퇴라는 거거든?","JPN":"おい！　勘違いすんなよ、ガリ勉！　これは作戦上の撤退ってやつだ！","ENG":"Hey! Let's get one thing straight, nerd! It's called a tactical retreat!","TWN":"喂！話可不能亂說，乖乖牌！這在戰術上稱為三十六計走為上策好嗎？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"뭐라고요!? 범생이!?","JPN":"はあ！？　ガリ勉！？","ENG":"What did you call me?! Nerd?!","TWN":"你叫我什麼！？乖乖牌！？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어이, 꼬마 대장! 무슨 대책 없어? 이대로는 결국 거점까지 밀고 들어올 거라고.","JPN":"おい、チビ隊長！　何か策はないのか？　このままじゃあ、拠点まで押し通されるぜ。","ENG":"Hey, Little Captain! What's the plan? They're going to attack our base at this rate.","TWN":"喂，小不點隊長！你沒有什麼對策嗎？再這樣下去，他們要直搗我們的據點咧！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이번 상대는 지금까지와는 달라요.","JPN":"今度の相手は今までとは違います。","ENG":"They're unlike any opponent we've faced so far.","TWN":"這次的對手和之前遇到的完全不同。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다들 총기류가 아닌 근접 무기에 두꺼운 갑옷까지 입고 있어서 대응이 어려워요.","JPN":"みんな、銃器類じゃなくて近接武器に、分厚い鎧まで着てるから対応するのが難しいんです。","ENG":"It's hard for us to deal with them when they have melee weapons and thick armor instead of guns.","TWN":"他們拿的不是槍枝，而是近距離作戰的武器，再加上身上厚重的鎧甲，要對付他們有點困難。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 꼬마라고 부르지마요! 콱 물어버릴 테니까!","JPN":"あと、チビって呼ばないでください！　嚙みますよ！","ENG":"And I dare you to call me little again! I'll bite you!","TWN":"然後，不要叫我小不點！當心我咬你！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"흥, 징징거리려면 이불 속에 들어가서 해.","JPN":"フン、弱音なら布団の中で吐けよ。","ENG":"Hmph. Go cry in your bed if you're gonna be whining.","TWN":"哼，說那麼多幹嘛，怕的話就回去睡大頭覺吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네가 여기 리더라면서? 팀을 여기까지 이끌고 온 거 아니야?","JPN":"お前がここのリーダーなんだろ？　チームをここまで率いてきたんじゃないのか？","ENG":"You're our leader, aren't you? You've brought the team all the way here, no?","TWN":"我聽說你是隊長？是你帶領團隊走到現在的吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리가 여기서 지면 부상 때문에 참가 못한 네 팀원은 무슨 죄냐?","JPN":"俺らがここで負けたら、怪我で参加できなかったお前のチームメンバーがかわいそうじゃねえか。","ENG":"If we lose here, what are you gonna tell your injured mate who couldn't join today, huh?","TWN":"我們要是輸掉的話，那那個因為受傷無法參賽的隊員不是很倒楣嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"되든 안 되든, 궁리를 짜내서 지시해.","JPN":"何でもいいから、知恵を絞って指示しろ。","ENG":"Doesn't matter if it works or not. Come up with a plan and give us the orders.","TWN":"不管怎麼樣，快點想辦法下指令！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"부탁도 받아들인 거, 네 장단에 어울려 줄테니까.","JPN":"一度引き受けたことだし、お前に付き合ってやるからよ。","ENG":"I'm already here. So, might as well dance to your rhythm.","TWN":"既然我已經答應幫忙，我就會配合你的指令。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트, 괜찮아요?","JPN":"フェリセット、大丈夫ですか？","ENG":"Félicette, are you okay?","TWN":"費莉塞特，你還好嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어른들은 다 참견쟁이야. 도와주러 온 주제에, 잘난 듯 잔소리만 실컷 하고.","JPN":"大人はみんなお節介よね。助けるために来たくせに、偉そうに小言ばっかりだし。","ENG":"All adults are nosy. They say they're here to help, but all they do is nag.","TWN":"大人真的很愛管閒事，明明是來幫忙的，卻一直說教。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만……. 이렇게 아마추어 같이 허접한 모습 보여주는 게 더 싫어.","JPN":"でも……こうやってアマチュアみたいなつまんない姿を見せるのはもっとイヤ。","ENG":"But... I don't want to be seen as some noob amateur.","TWN":"但是……我更討厭自己看起來像是一個窩囊的業餘選手。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음? 사장님한테서 통신이?","JPN":"ううん？　社長から通信？","ENG":"Hmm? It's Boss calling.","TWN":"嗯？你打給老闆喔？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어떤가, 펠리세트? 이제 생각이 좀 정리됐나?","JPN":"どうだい、フェリセット？　少しは心の整理がついたか？","ENG":"How are you doing, Félicette? Have you gotten your thoughts in order?","TWN":"怎麼樣，費莉塞特？你想好了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이제부터 우리도 반격을 시작해야겠지?","JPN":"ここからはこちらからも反撃を始めないとな。","ENG":"It's time to start our counterattack, right?","TWN":"接下來該換我們反擊了吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네, 코치.","JPN":"はい、コーチ。","ENG":"Yes, Coach.","TWN":"是，教練。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"처음부터 정직하게 정면으로 나오는 상대에게 이것저것 생각할 필요 없었어요.","JPN":"最初から正直に正面から攻めて来る相手に、あれこれ考える必要なんかなかったんです。","ENG":"I didn't need to think so much about how to deal with an opponent who keeps charging straight at us.","TWN":"對於正面對決的對手不需要想太多。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"우리도 정면으로 승부하겠습니다.","JPN":"私たちも正面から勝負します。","ENG":"We'll simply fight them head-on.","TWN":"我們也正面對決一較高下吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그러다가 진다면?","JPN":"……それで負けたら？","ENG":"...And if we lose because of that?","TWN":"……萬一輸掉的話呢？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"상관없어요.","JPN":"構いません。","ENG":"It doesn't matter.","TWN":"無所謂。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"카운터가 둘이나 더 붙었는데 저 사람들과의 정면 승부에서 진다면…….","JPN":"カウンターが二人も増えたのに、あの人たちに正面勝負で負けるなら……","ENG":"We got two more Counters on our team. If we lose to them...","TWN":"我們隊上有二個制裁者，這樣還輸掉的話……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"오지만디아스에게는 가까이 가지도 못 할 거예요.","JPN":"オジマンディアスにはまったく近づけないはずですから。","ENG":"Then it'll be impossible to get any closer to Ozymandias.","TWN":"就表示我們還不夠格挑戰奧茲曼迪亞斯。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래요! 펠리세트! 이번에도 이기면 건틀렛 결승에 한 발짝 더 다가가는 거예요!","JPN":"そうですよ！　フェリセット！　今度勝ったら、ガントレット決勝にまた一歩近づくわけです！","ENG":"That's right! Félicette! By winning this match, we'll be one step closer to the Gauntlet finals!","TWN":"沒錯！費莉塞特！這次也贏的話，就離聖鎧決賽更近一步囉！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트의 꿈을 위해서, 이 노엘! 마지막까지 열심히 하겠습니다!","JPN":"フェリセットの夢のために、このノエル！　最後まで頑張ります！","ENG":"To fulfill Félicette's dream, I, Noelle! Will do my best until the end!","TWN":"我洛艾兒！會為費莉塞特的夢想而努力的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……마워.","JPN":"……がとう。","ENG":"–anks.","TWN":"……謝。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"啥？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아, 아냐!","JPN":"う、ううん！","ENG":"N-nothing!","TWN":"沒，沒事！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"좋아요, 다들 준비해요! 이번 충돌로 승부를 내겠어요!","JPN":"よし、みんな準備してください！　今回の衝突で勝負を決めます！","ENG":"Okay. Everyone get ready! This last fight will either make or break us!","TWN":"好，大家準備！這次的交鋒就要分出勝負！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};